where.if:
AND EXISTS (
    SELECT 1
    FROM expense_items ei_from
    WHERE ei_from.expense_application_id = ea.id
      AND ei_from.expense_date >= #{condition.expenseDateFrom}
)

AND EXISTS (
    SELECT 1
    FROM expense_items ei_to
    WHERE ei_to.expense_application_id = ea.id
      AND ei_to.expense_date <= #{condition.expenseDateTo}
)

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM expense_applications
    WHERE id = #{id}
      AND status = #{status}
)
